const express = require('express');
const winston = require('winston');

// Create a logger instance
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.printf(info => `${info.timestamp} - ${info.level}: ${info.message}`),
  ),
  transports: [
    new winston.transports.File({ filename: 'logs/combined.log' }),
    new winston.transports.Console(),
  ],
});

const app = express();

// Middleware to log requests
app.use((req, res, next) => {
  const user = req.body.user || '';
  const ip = req.ip;
  const headers = Object.keys(req.headers).map(key => `${key}: ${req.headers[key]}`);
  logger.info(`User: ${user}, IP: ${ip}, Headers: ${headers.join(', ')}`);
  next();
});

// Route to accept user input
app.post('/log', (req, res) => {
  const { message } = req.body;
  if (!message) return res.status(400).send('Missing required field');
  logger.info(message);
  res.send('Log recorded successfully');
});

const port = process.env.PORT || 3000;

app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});